CREATE TABLE "rep_sym" (
  "rep_id" integer  NOT NULL,
  "sym_id" integer  NOT NULL,
  "degree" smallint  NOT NULL DEFAULT '1'
);
CREATE TABLE "repertorizations" (
  "patient_id" char(5) NOT NULL,
  "rep_id" integer  NOT NULL ,
  "rep_note" text NOT NULL,
  "rep_prescription" text NOT NULL,
  "rep_public" smallint  NOT NULL DEFAULT '0',
  "sym_table" varchar(255) NOT NULL,
  "username" varchar(30) NOT NULL,
  "rep_timestamp" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("rep_id")
);
CREATE TABLE "skins" (
  "skin_id" smallint  NOT NULL ,
  "skin_name" varchar(30) NOT NULL,
  "phorum_template" varchar(30) NOT NULL,
  "skin_author" text NOT NULL,
  "skin_year" varchar(9) NOT NULL,
  "skin_version" varchar(30) NOT NULL,
  "skin_copyright" text NOT NULL,
  "skin_license" text NOT NULL,
  "skin_description" text NOT NULL,
  "username" varchar(30) NOT NULL,
  "timestamp" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("skin_id")
);
INSERT INTO "skins" VALUES (1,'original','embed_homeophorum','Henri Schumacher','2006-2014','1.0','Henri Schumacher','AGPLv3','Original-Skin von Openhomeopath vom Autor','admin','2014-05-24 18:00:00'),(2,'kraque','kraque','Thomas Bochmann','2009','1.0','Thomas Bochmann','AGPLv3','','thomas2','2014-05-24 18:00:00');
CREATE TABLE "sources" (
  "src_no" smallint  NOT NULL ,
  "src_id" varchar(12) NOT NULL,
  "src_title" varchar(200) NOT NULL,
  "lang_id" varchar(6) NOT NULL,
  "src_type" varchar(30) NOT NULL DEFAULT 'Repertorium',
  "grade_max" smallint  NOT NULL,
  "src_author" text NOT NULL,
  "src_year" varchar(9) NOT NULL DEFAULT '0',
  "src_edition_version" text NOT NULL,
  "src_copyright" text NOT NULL,
  "src_license" text NOT NULL,
  "src_url" text NOT NULL,
  "src_isbn" text NOT NULL,
  "src_proving" text NOT NULL,
  "src_note" text NOT NULL,
  "src_contact" text NOT NULL,
  "primary_src" smallint NOT NULL DEFAULT '1',
  "username" varchar(30) NOT NULL,
  "timestamp" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("src_id")
);
INSERT INTO "sources" VALUES (1,'BZH','BZ-Homöopathie','de','Repertorium / Repertory',3,'Bernd Zille','1998-2000','1.01a','Bernd Zille Software','Die Lizenz zu nicht kommerziellen Zwecken wurde für OpenHomeopath erteilt (03.2007).\r\nDie Nutzung unserer Daten durch Zugriff auf die Datenbank von OpenHomeopath wird hierbei auch beruflich tätigen Homöopathen und Heilern gestattet.\r\n','http://www.zille-software.de','','','Datenbank des Programms \"BZ-Homöopathie für Windows\".\r\nWeitere Informationen auf der Homepage des Autors www.zille-software.de.','bernd.zille@zille-software.de',1,'admin','2014-05-27 16:03:38'),(2,'kent.en','Homeopathic Repertory','en','Repertorium / Repertory',3,'Kent James Tyler','','','','open source repertory','','','','','',1,'kraque','2014-05-27 16:03:38'),(3,'kent.de','openrep kent.en translation','de','Repertorium / Repertory',3,'bergische-akademie','2011','RC2','','open source','http://bergische-akademie.github.com/OpenRep-Deutsch/','','','OpenRep Deutsch RC2 inkl. deutschem Kent\r\n','',1,'kraque','2014-05-27 16:03:38'),(4,'openrep_pub','Repertorium publicum 0.9','en','Repertorium / Repertory',3,'Vladimir Polony','2009','0.9','','open source repertory','','','','','',1,'kraque','2014-05-27 16:03:38'),(5,'synt91.de','Synthesis 9.1','de','Repertorium / Repertory',4,'Frederik Schroyens','2005','Edition','Hahnemann Institut GmbH','','','3-929271-13-3','','','',1,'thomas2','2014-05-27 16:03:38'),(6,'synt91.en','Synthesis 9.1 english','en','Repertorium / Repertory',4,'Frederik Schroyens','2004','9.1','Homeopathic Book  Publishers, London','','','1-902575-15-6','','Repertorium Homeopathicum Syntheticum, Edition 9.1 ','',1,'kraque','2014-05-27 16:03:38'),(7,'murphy','Klinisches Repertorium der Homöopathie','de','Repertorium / Repertory',4,'Murphy Robin','2007','1','Narayana Verlag','','http://narayana-verlag.de/Klinisches-Repertorium-der-Homoeopathie/Murphy-Robin/b2534','978-3-921383-98-8','','Übersetzung Andreas Maier\r\nÜberarbeitung Lorenz Pollak','Narayana Verlag GmbH, Blumenplatz 2, 79400 Kandern',1,'kraque','2014-05-27 16:03:38'),(8,'boenn_allen','Bönninghausen’s Therapeutic Pocketbook T.F.Allen (Ed.)','en','Repertorium / Repertory',4,'T.F.Allen','1891','','','open source repertory','','','','Bönninghausen’s Therapeutic Pocketbook..., T.F.Allen (Ed.), Philadelphia, 1891 ','',1,'kraque','2014-05-27 16:03:38'),(9,'boenn_bogner','Boger, Boenninghausen''s Repertory (1937)','en','Repertorium / Repertory',5,'Cyrus Maxwell Boger','1937','','','open source repertory','','','','A truly unique repertory that uses the characteristic approach of Boenninghausen. Version from 1937 including Dunham''s notes','',1,'kraque','2014-05-27 16:03:38'),(10,'bl3.de','Homöopathische Grippemittel','de','Publikation / Publication',0,'Borland, Douglas M.','2009','1. Aufl. 15.01.2009','Narayana','\r\n','http://www.narayana-verlag.de/Borland%2C+Douglas+M./Hom%26ouml%3Bopathische+Grippemittel/b4676','978-3-939931-76-8','','mit Beiträgen von Radke, Dagmar / Oomen\r\nEinband :  	Kartoniert\r\nPreisinfo :  	9,80 Eur[D] / 10,10 Eur[A]\r\nSonstige Preise :  	8,00\r\nSeiten/Umfang :  	96 S. - 18 x 11 cm\r\nErschienen :  	1. Aufl. 15.01.2009','',1,'thomas2','2014-05-27 16:06:52'),(11,'pers1','Die homöopathische Behandlung der Grippe','de','Publikation / Publication',0,'Perko, Sandra','2007','1. Aufl. 30.11.2007','Narayana','','http://www.narayana-verlag.de/Perko%2C+Sandra/Die+hom%26ouml%3Bopathische+Behandlung+der+Grippe/b325','978-3-939931-04-1','','Perko, Sandra\r\nDie homöopathische Behandlung der Grippe\r\nMit einem Sonderteil über Vogelgrippe\r\nVerlag :   	  Narayana\r\nISBN :  	978-3-939931-04-1\r\nEinband :  	Gebunden\r\nPreisinfo :  	29,00 Eur[D] / 29,90 Eur[A]\r\n\r\nSeiten/Umfang :  	ca. 500 S. - 21 x 14,8 cm\r\nErschienen :  	1. Aufl. 30.11.2007','',1,'thomas2','2014-05-27 16:06:52'),(12,'fd5','=fd5.de= Charaktere Homöopathischer Arzneimittel Teil V','de','alias',0,'Friedrich Peter Und Edeltraud','0','','','','','','','','',1,'admin','1970-01-01 00:00:00'),(13,'gl1','=gl1.fr= Psychisme et Homéopathie','fr','alias',0,'Gallavardin Jean-Pierre  	','1896','','','','','','','','',1,'admin','1970-01-01 00:00:00'),(14,'szs1','The proving of Musca domestica','en','Arzneimittelprüfung / Proving',0,'Sonz Susan And Stewart Robert','2002','','New York Luminos School of Homeopathy','','http://www.nyhomeopathy.com/flysum.htm','','','The proving of Musca domestica, ( 2002)','',1,'kraque','2014-05-27 16:10:59'),(15,'szs-oh1','Didelphis Virginiana: a proving of Virginia Opossum','en','Arzneimittelprüfung / Proving',1,'Susan Sonz and Mary-Lynn Culbert\r\n','2008','','The New York School of Homeopathy','','http://www.nyhomeopathy.com/opossum_sum.htm','','','with help from Patricia Monahan','',1,'kraque','2014-05-27 16:10:59'),(16,'huen-1','Proving of Acer saccharum, Sugar Maple','en','Arzneimittelprüfung / Proving',1,'Jason-Aeric Huenecke','2008','','Northwestern Academy of Homeopathy','','http://www.homeovista.org/provings/html/acer_saccharum_proving.html','','','PREPARATION\r\nSarah Weis prepared the substance for the proving in Montana by trituration in lactose up to 3C, and then attenuated it in 95% pure grain alcohol to 30C according to Hahnemannian principles on 23 September 2008\r\n\r\nCOMPILATION\r\n\r\nSuzanne Joyce and Deborah Benedict, with students and alumni of the Northwestern Academy of Homeopathy\r\n\r\nMETHODOLOGY\r\n\r\nSixteen provers took the remedy administered in 6C, 12C, and 30C potencies. The proving was double precision blind format in which neither the supervisors nor the provers were aware of the substance they were taking. During the proving, provers logged symptoms on a daily basis and were in daily contact with their supervisor until symptoms subsided.\r\nREMEDY AVAILABILITY\r\n* NAH Pharmacy (763-746-9242)\r\n* Helios Homeopathy Ltd, Contact\r\n* 360 Homeopathy, Sara Weis (1-406-582-5499) ','',1,'kraque','2014-05-27 16:10:59'),(17,'huen-2','Proving of Chelydra serpentina, Snapping Turtle','en','Arzneimittelprüfung / Proving',1,'Jason-Aeric Huenecke','2004','','Northwestern Academy of Homeopathy','','http://www.homeovista.org/provings/html/chelydra_proving.html','','','Remedy Abbreviation: chely-sp-o\r\n\r\nNorthwestern Academy of Homeopathy\r\n2004\r\nMASTER PROVER\r\n\r\nEric Sommermann, PhD, RSHom (NA)\r\nSOURCE\r\n\r\n10-15 snapping turtle eggs from Northern Minnesota; provided by Alex Lanning (alumnus).\r\nCOMPILATION\r\n\r\nTeresa Stewart and students of the Northwestern Academy of Homeopathy.  Themework by Lori Foley and Sandra Haering.\r\n\r\nMETHODOLOGY\r\n\r\nSixteen provers took the remedy administered in 6C, 12C, and 30C potencies. The proving was double precision blind format in which neither the supervisors nor the provers were aware of the substance they were taking. During the proving, provers logged symptoms on a daily basis and were in daily contact with their supervisor until symptoms subsided.\r\nREMEDY AVAILABILITY\r\n\r\nNAH Pharmacy (763-746-9242)\r\n360 Homeopathy, Sara Weis (1-406-582-5499)','',1,'kraque','2014-05-27 16:10:59'),(100,'aem','( 1952-)','','Sonstiges / Others',0,'Ache M.','','','','','','','','( 1952-)','',0,'admin','2014-05-27 16:12:23'),(101,'aem1','Proving of Aegopodium podagria, Documenta Homoeop','en','Sonstiges / Others',0,'Ache M. And Mattitsch G.','1989','','','','','','','Proving of Aegopodium podagria, Documenta Homoeopathica, 12 ( 1989)','',0,'admin','2014-05-27 16:12:23'),(102,'az1.de','Carcinosinum, H Einblicke','de','Sonstiges / Others',0,'Achtzehn Hans-Jürgen','1990','','','','','','','Carcinosinum, H Einblicke, Vol 1: pg 6 ( 1990)','',0,'admin','2014-05-27 16:12:23'),(103,'az','Achtzehn Hans-Jürgen','','Autor / Author',0,'Achtzehn Hans-Jürgen','1951-','','','','','','','Zeitgenössischer Homöopath [Deutschland] ( 1951-)','',0,'admin','2014-05-27 16:09:49'),(104,'acl','Ackerly Sarah','','Autor / Author',0,'Ackerly Sarah','','','','','','','','Zeitgenössische Homöopathin [Portland, U